WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
See the License for the specific language governing permissions and
limitations under the License.
*/

package main

import (
	"context"
	"encoding/base64"
	"testing"
	"time"

	"github.com/jonboulle/clockwork"
	"github.com/stretchr/testify/require"

	"github.com/gravitational/teleport"
	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
	"github.com/gravitational/teleport/lib/auth/mocku2f"
	"github.com/gravitational/teleport/lib/auth/u2f"
	"github.com/gravitational/teleport/lib/services"
)

// TestRegression demonstrates the multi-device U2F authentication bug.
// When a user registers multiple U2F tokens, only the first token is issued
// a challenge during login, preventing use of other registered devices.
func TestRegression(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create test auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Set up U2F configuration
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "testuser", []string{"role"})
	require.NoError(t, err)
	username := user.GetName()

	// Get U2F config from auth server
	u2fConfig, err := as.AuthServer.GetAuthPreference()
	require.NoError(t, err)
	u2fPref, err := u2fConfig.GetU2F()
	require.NoError(t, err)

	// Get the Identity backend for storage
	identityBackend := as.AuthServer.Identity

	// Create in-memory storage for U2F challenges
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(identityBackend)
	require.NoError(t, err)

	// Register first U2F device
	u2fDev1, err := mocku2f.Create()
	require.NoError(t, err)

	// Perform first registration
	regChallenge1, err := u2f.NewChallenge(u2fPref.AppID, u2fPref.Facets)
	require.NoError(t, err)
	regResp1, err := u2fDev1.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: regChallenge1.Challenge,
		AppID:     regChallenge1.AppID,
	})
	require.NoError(t, err)

	mfaDev1, err := u2f.NewDevice("u2f-device-1", &u2f.Registration{
		KeyHandle: u2fDev1.KeyHandle,
		PubKey:    u2fDev1.PrivateKey.PublicKey,
	}, clock.Now())
	require.NoError(t, err)

	// Store first device
	err = identityBackend.UpsertMFADevice(ctx, username, mfaDev1)
	require.NoError(t, err)

	// Register second U2F device
	u2fDev2, err := mocku2f.Create()
	require.NoError(t, err)

	regChallenge2, err := u2f.NewChallenge(u2fPref.AppID, u2fPref.Facets)
	require.NoError(t, err)
	regResp2, err := u2fDev2.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: regChallenge2.Challenge,
		AppID:     regChallenge2.AppID,
	})
	require.NoError(t, err)

	mfaDev2, err := u2f.NewDevice("u2f-device-2", &u2f.Registration{
		KeyHandle: u2fDev2.KeyHandle,
		PubKey:    u2fDev2.PrivateKey.PublicKey,
	}, clock.Now())
	require.NoError(t, err)

	// Store second device
	err = identityBackend.UpsertMFADevice(ctx, username, mfaDev2)
	require.NoError(t, err)

	// Verify both devices are stored
	devs, err := as.AuthServer.GetMFADevices(ctx, username)
	require.NoError(t, err)
	u2fDevices := make([]*types.MFADevice, 0)
	for _, dev := range devs {
		if dev.GetU2F() != nil {
			u2fDevices = append(u2fDevices, dev)
		}
	}
	require.Len(t, u2fDevices, 2, "Expected 2 U2F devices to be registered")

	// TEST 1: Old API (CheckU2FSignChallenge) - only returns challenge for FIRST device
	// This demonstrates the bug: only one challenge is returned even though user has 2 devices
	challenge1, err := as.AuthServer.CheckU2FSignChallenge(ctx, username)
	require.NoError(t, err)
	require.NotNil(t, challenge1)

	// The challenge should be for only one device (the bug!)
	// Extract which device this challenge is for
	if challenge1 == nil {
		t.Fatal("Challenge should not be nil")
	}

	challenge1KeyHandle := challenge1.KeyHandle
	challenge1Matches := false
	for _, dev := range u2fDevices {
		u2fDev := dev.GetU2F()
		kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		if kh == challenge1KeyHandle {
			challenge1Matches = true
			break
		}
	}
	require.True(t, challenge1Matches, "Challenge should match one of the registered devices")

	// TEST 2: New API (CreateAuthenticateChallenge) - correctly returns challenges for ALL devices
	// This is the fixed implementation that properly supports multi-device U2F
	challenge2, err := as.AuthServer.CreateAuthenticateChallenge(ctx, username, false)
	require.NoError(t, err)
	require.NotNil(t, challenge2)

	// The challenge should have U2F challenges for BOTH devices (this is the correct behavior)
	require.NotEmpty(t, challenge2.U2F, "Challenge should contain U2F challenges")

	// This test demonstrates the regression: we expect the number of U2F challenges
	// to match the number of registered U2F devices
	expectedDeviceCount := 2
	actualChallengeCount := len(challenge2.U2F)

	if actualChallengeCount != expectedDeviceCount {
		t.Logf("REGRESSION BUG DETECTED:")
		t.Logf("Expected %d U2F challenges for %d registered devices", expectedDeviceCount, expectedDeviceCount)
		t.Logf("Got %d U2F challenges", actualChallengeCount)
		t.Logf("This means only %d/%d registered U2F devices can be used during authentication", actualChallengeCount, expectedDeviceCount)

		// This should fail on buggy code and pass on fixed code
		t.Errorf("Multi-device U2F authentication regression: expected %d challenges, got %d", expectedDeviceCount, actualChallengeCount)
	}

	// Verify that the challenges are for different devices (not duplicates)
	challengeKeyHandles := make(map[string]bool)
	for _, ch := range challenge2.U2F {
		challengeKeyHandles[ch.KeyHandle] = true
	}
	require.Len(t, challengeKeyHandles, expectedDeviceCount, "All U2F challenges should be for different devices")

	// Verify all registered devices have challenges
	for _, dev := range u2fDevices {
		u2fDev := dev.GetU2F()
		deviceKeyHandle := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		require.True(t, challengeKeyHandles[deviceKeyHandle], "Every registered U2F device should have a challenge")
	}

	// TEST 3: Demonstrate client/server compatibility issue
	// When client sends response for device 2, but server only issued challenge for device 1
	authChallenge1, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
		AppConfig:  *u2fPref,
		Dev:        mfaDev1,
		StorageKey: username,
		Storage:    u2fStorage,
	})
	require.NoError(t, err)

	// Try to authenticate with device 1
	authResp1, err := u2fDev1.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: authChallenge1.Challenge,
		KeyHandle: authChallenge1.KeyHandle,
		AppID:     authChallenge1.AppID,
	})
	require.NoError(t, err)

	// This should work - device 1 authentication succeeds
	err = u2f.AuthenticateVerify(ctx, u2f.AuthenticateVerifyParams{
		Dev:        mfaDev1,
		Resp:       authResp1,
		StorageKey: username,
		Storage:    u2fStorage,
		Clock:      clock,
	})
	require.NoError(t, err, "Device 1 authentication should succeed")

	// Now try with device 2 - this demonstrates the problem
	// If the client only received a challenge for device 1, it cannot use device 2
	authChallenge2, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
		AppConfig:  *u2fPref,
		Dev:        mfaDev2,
		StorageKey: username,
		Storage:    u2fStorage,
	})
	require.NoError(t, err)

	authResp2, err := u2fDev2.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: authChallenge2.Challenge,
		KeyHandle: authChallenge2.KeyHandle,
		AppID:     authChallenge2.AppID,
	})
	require.NoError(t, err)

	// This should work - device 2 authentication succeeds
	err = u2f.AuthenticateVerify(ctx, u2f.AuthenticateVerifyParams{
		Dev:        mfaDev2,
		Resp:       authResp2,
		StorageKey: username,
		Storage:    u2fStorage,
		Clock:      clock,
	})
	require.NoError(t, err, "Device 2 authentication should succeed when properly challenged")

	// Log success message
	t.Logf("Regression test completed")
	t.Logf("- Multiple U2F devices can be registered: PASS")
	t.Logf("- Both devices can authenticate individually: PASS")
	t.Logf("- Old API returns only 1 challenge for 2 devices: CONFIRMED (BUG)")
	t.Logf("- New API returns correct number of challenges: %v", actualChallengeCount == expectedDeviceCount)
}

